namespace sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public PersonalInfo ToRecord() => new(FullName, Email, Phone, Address);
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public WorkEntry ToRecord() => new(Company, Title, StartDate!.Value, IsCurrent ? null : EndDate, Description);
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public Reference ToRecord() => new(Name, Relationship, Email, Phone);
}

@namespace sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Components.Pages.Apply

<nav aria-label="Application progress" class="step-indicator mb-4">
    <ol class="d-flex list-unstyled justify-content-between position-relative">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepNumber = i + 1;
            var isActive = stepNumber == CurrentStep;
            var isCompleted = CompletedSteps.Contains(stepNumber);
            var isFuture = !isActive && !isCompleted;

            <li class="step-item text-center flex-fill @(isActive ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
                @onclick="() => HandleStepClick(stepNumber)"
                role="button"
                tabindex="@(isCompleted ? 0 : -1)"
                aria-current="@(isActive ? "step" : null)">
                <div class="step-circle mx-auto mb-1 d-flex align-items-center justify-content-center rounded-circle @(isActive ? "bg-primary text-white" : "") @(isCompleted ? "bg-success text-white" : "") @(isFuture ? "bg-light text-muted border" : "")">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@stepNumber</span>
                    }
                </div>
                <small class="@(isFuture ? "text-muted" : "") @(isActive ? "fw-bold" : "")">@StepNames[i]</small>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private async Task HandleStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

@namespace sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Components.Pages.Apply

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Reference @(Index + 1)</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Reference.Name" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Reference.Relationship" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="Reference.Email" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" @bind="Reference.Phone" @bind:event="oninput" />
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ReferenceModel Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

@using sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Models

@namespace sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Components.Pages.Apply

<div>
    <h4 class="mb-3">Personal Information</h4>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    <div class="row g-3">
        <div class="col-md-6">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input type="text" class="form-control @(fieldErrors.ContainsKey("FullName") ? "is-invalid" : "")"
                   @bind="Model.FullName" @bind:event="oninput" />
            @if (fieldErrors.TryGetValue("FullName", out var nameError))
            {
                <div class="invalid-feedback">@nameError</div>
            }
        </div>
        <div class="col-md-6">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control @(fieldErrors.ContainsKey("Email") ? "is-invalid" : "")"
                   @bind="Model.Email" @bind:event="oninput" />
            @if (fieldErrors.TryGetValue("Email", out var emailError))
            {
                <div class="invalid-feedback">@emailError</div>
            }
        </div>
        <div class="col-md-6">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control @(fieldErrors.ContainsKey("Phone") ? "is-invalid" : "")"
                   @bind="Model.Phone" @bind:event="oninput" />
            @if (fieldErrors.TryGetValue("Phone", out var phoneError))
            {
                <div class="invalid-feedback">@phoneError</div>
            }
        </div>
        <div class="col-md-6">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <input type="text" class="form-control @(fieldErrors.ContainsKey("Address") ? "is-invalid" : "")"
                   @bind="Model.Address" @bind:event="oninput" />
            @if (fieldErrors.TryGetValue("Address", out var addressError))
            {
                <div class="invalid-feedback">@addressError</div>
            }
        </div>
    </div>

    <div class="d-flex justify-content-end mt-4">
        <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
            @if (isValidating)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <span>Validating…</span>
            }
            else
            {
                <span>Next</span>
            }
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private Dictionary<string, string> fieldErrors = new();
    private string? errorMessage;
    private bool isValidating;

    private async Task HandleNext()
    {
        fieldErrors.Clear();
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName))
            fieldErrors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Model.Email))
            fieldErrors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Model.Phone))
            fieldErrors["Phone"] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(Model.Address))
            fieldErrors["Address"] = "Address is required.";

        if (fieldErrors.Count > 0)
            return;

        isValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!emailValid)
            {
                fieldErrors["Email"] = "This email address is not valid.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        catch
        {
            errorMessage = "An error occurred while validating your email. Please try again.";
        }
        finally
        {
            isValidating = false;
        }
    }
}

@using sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Models

@namespace sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Components.Pages.Apply

<div>
    <h4 class="mb-3">Work History</h4>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryEditor Entry="Entries[index]"
                         Index="index"
                         CanRemove="Entries.Count > 1"
                         OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
        + Add Another Position
    </button>

    <div class="d-flex justify-content-between mt-4">
        <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) ||
                string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate is null)
            {
                errorMessage = "Each position must have a company name, job title, and start date.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Models

@namespace sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Components.Pages.Apply

<div>
    <h4 class="mb-3">References</h4>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceEditor Reference="References[index]"
                         Index="index"
                         CanRemove="References.Count > 2"
                         OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
            + Add Reference
        </button>
    }

    <div class="d-flex justify-content-between mt-4">
        <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errorMessage = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) ||
                string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) ||
                string.IsNullOrWhiteSpace(r.Phone))
            {
                errorMessage = "All fields are required for each reference.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Models

@namespace sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Components.Pages.Apply

<div>
    <h4 class="mb-3">Cover Letter</h4>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    <div class="mb-3">
        <textarea class="form-control" rows="10" maxlength="@MaxLength"
                  @bind="CoverLetter" @bind:event="oninput"
                  @bind:after="NotifyChanged"
                  placeholder="Write your cover letter here…"></textarea>
        <div class="form-text text-end">
            @(CoverLetter?.Length ?? 0) / @MaxLength characters
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private const int MaxLength = 2000;
    private string? errorMessage;

    private async Task NotifyChanged()
    {
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }

    private async Task HandleNext()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            errorMessage = "Please write a cover letter before continuing.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Components.Pages.Apply

<div>
    <h4 class="mb-3">Review &amp; Submit</h4>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    @* Personal Info *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    @* Work History *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-no-border">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted">
                        @entry.StartDate?.ToString("MMM yyyy") &mdash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="mt-1">@entry.Description</div>
                    }
                </div>
            }
        </div>
    </div>

    @* References *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) &mdash; @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    @* Cover Letter *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(4)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button type="button" class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Application</span>
            }
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
