@namespace sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Components.Pages.Apply

<div>
    <h4 class="mb-3">Personal Information</h4>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    <div class="row g-3">
        <div class="col-md-6">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input type="text" class="form-control @(fieldErrors.ContainsKey("FullName") ? "is-invalid" : "")"
                   @bind="Model.FullName" @bind:event="oninput" />
            @if (fieldErrors.TryGetValue("FullName", out var nameError))
            {
                <div class="invalid-feedback">@nameError</div>
            }
        </div>
        <div class="col-md-6">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control @(fieldErrors.ContainsKey("Email") ? "is-invalid" : "")"
                   @bind="Model.Email" @bind:event="oninput" />
            @if (fieldErrors.TryGetValue("Email", out var emailError))
            {
                <div class="invalid-feedback">@emailError</div>
            }
        </div>
        <div class="col-md-6">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control @(fieldErrors.ContainsKey("Phone") ? "is-invalid" : "")"
                   @bind="Model.Phone" @bind:event="oninput" />
            @if (fieldErrors.TryGetValue("Phone", out var phoneError))
            {
                <div class="invalid-feedback">@phoneError</div>
            }
        </div>
        <div class="col-md-6">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <input type="text" class="form-control @(fieldErrors.ContainsKey("Address") ? "is-invalid" : "")"
                   @bind="Model.Address" @bind:event="oninput" />
            @if (fieldErrors.TryGetValue("Address", out var addressError))
            {
                <div class="invalid-feedback">@addressError</div>
            }
        </div>
    </div>

    <div class="d-flex justify-content-end mt-4">
        <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
            @if (isValidating)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <span>Validating…</span>
            }
            else
            {
                <span>Next</span>
            }
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private Dictionary<string, string> fieldErrors = new();
    private string? errorMessage;
    private bool isValidating;

    private async Task HandleNext()
    {
        fieldErrors.Clear();
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName))
            fieldErrors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Model.Email))
            fieldErrors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Model.Phone))
            fieldErrors["Phone"] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(Model.Address))
            fieldErrors["Address"] = "Address is required.";

        if (fieldErrors.Count > 0)
            return;

        isValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!emailValid)
            {
                fieldErrors["Email"] = "This email address is not valid.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        catch
        {
            errorMessage = "An error occurred while validating your email. Please try again.";
        }
        finally
        {
            isValidating = false;
        }
    }
}

