@namespace sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Components.Pages.Apply

<div>
    <h4 class="mb-3">Cover Letter</h4>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    <div class="mb-3">
        <textarea class="form-control" rows="10" maxlength="@MaxLength"
                  @bind="CoverLetter" @bind:event="oninput"
                  @bind:after="NotifyChanged"
                  placeholder="Write your cover letter here…"></textarea>
        <div class="form-text text-end">
            @(CoverLetter?.Length ?? 0) / @MaxLength characters
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private const int MaxLength = 2000;
    private string? errorMessage;

    private async Task NotifyChanged()
    {
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }

    private async Task HandleNext()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            errorMessage = "Please write a cover letter before continuing.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

