@namespace sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Components.Pages.Apply

<div>
    <h4 class="mb-3">Review &amp; Submit</h4>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    @* Personal Info *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    @* Work History *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-no-border">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted">
                        @entry.StartDate?.ToString("MMM yyyy") &mdash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="mt-1">@entry.Description</div>
                    }
                </div>
            }
        </div>
    </div>

    @* References *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) &mdash; @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    @* Cover Letter *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(4)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button type="button" class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Application</span>
            }
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public EventCallback OnSubmit { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEditSection { get; set; }

    private string? errorMessage;
}

@using sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Models

arguments.file_text:
@page "/apply"
@rendermode InteractiveServer
@using sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Models
@using sv_a7bf1ca6cdfb45acb5b4839e1edda96a.Components.Pages.Apply
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @if (isSubmitted)
    {
        <div class="alert alert-success text-center py-5">
            <h3 class="mb-3">&#10003; Application Submitted!</h3>
            <p class="lead">Your application has been received.</p>
            <p>Your application ID is: <strong>@applicationId</strong></p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="currentStep"
                       CompletedSteps="completedSteps"
                       OnStepClicked="GoToStep" />

        @switch (currentStep)
        {
            case 1:
                <PersonalInfoStep Model="personalInfo"
                                  ApplicationService="ApplicationService"
                                  OnNext="() => CompleteAndAdvance(1)" />
                break;
            case 2:
                <WorkHistoryStep Entries="workEntries"
                                 OnBack="() => GoToStep(1)"
                                 OnNext="() => CompleteAndAdvance(2)" />
                break;
            case 3:
                <ReferencesStep References="references"
                                OnBack="() => GoToStep(2)"
                                OnNext="() => CompleteAndAdvance(3)" />
                break;
            case 4:
                <CoverLetterStep @bind-CoverLetter="coverLetter"
                                 OnBack="() => GoToStep(3)"
                                 OnNext="() => CompleteAndAdvance(4)" />
                break;
            case 5:
                <ReviewStep Personal="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="coverLetter"
                            IsSubmitting="isSubmitting"
                            OnBack="() => GoToStep(4)"
                            OnSubmit="HandleSubmit"
                            OnEditSection="GoToStep" />
                break;
        }
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = "";

    private bool isSubmitting;
    private bool isSubmitted;
    private int? applicationId;

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private void CompleteAndAdvance(int step)
    {
        completedSteps.Add(step);
        currentStep = step + 1;
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        try
        {
            var application = new JobApplication(
                personalInfo.ToRecord(),
                new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
                references.Select(r => r.ToRecord()).ToList(),
                coverLetter
            );

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            isSubmitted = true;
        }
        catch
        {
            // Error is displayed in ReviewStep
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

::deep .step-indicator ol {
    counter-reset: step;
    margin: 0;
    padding: 0;
}

::deep .step-item {
    position: relative;
    cursor: default;
}

::deep .step-item.completed {
    cursor: pointer;
}

::deep .step-circle {
    width: 36px;
    height: 36px;
    font-size: 0.875rem;
    font-weight: 600;
    transition: background-color 0.2s, color 0.2s;
}

::deep .step-item.future .step-circle {
    background-color: #e9ecef;
    color: #6c757d;
}

::deep .step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: calc(50% + 22px);
    width: calc(100% - 44px);
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

::deep .step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

